import{_ as i,o as e,c as a,ai as t,ak as n,al as l,am as o}from"./chunks/framework.CKB5fCPB.js";const y=JSON.parse('{"title":"Getting started","description":"","frontmatter":{},"headers":[],"relativePath":"Getting started.md","filePath":"Getting started.md"}'),h={name:"Getting started.md"};function r(p,s,d,c,k,u){return e(),a("div",null,[...s[0]||(s[0]=[t(`<h1 id="getting-started" tabindex="-1">Getting started <a class="header-anchor" href="#getting-started" aria-label="Permalink to “Getting started”">​</a></h1><p>This document explains how to get started with the chat application and explain some concepts. If you ever need help you can make a post on <a href="https://www.reddit.com/r/dcts/" target="_blank" rel="noreferrer">our subreddit</a>.</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p></p><p>There&#39;s now an official <a href="https://www.youtube.com/watch?v=b1RXJ-ykdgc&amp;list=PL2xF-BCo1FWav36ktSvBG4nDsbhfLkFR-" target="_blank" rel="noreferrer">Youtube Tutorial playlist</a> which is recommended! It will simply the setup massively.</p></div><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p></p><p>Always stop the server before editing the <em><code>config.json</code></em> file. Data may be overwritten otherwise!</p></div><hr><h2 id="requirements-recommendations" tabindex="-1">Requirements &amp; Recommendations <a class="header-anchor" href="#requirements-recommendations" aria-label="Permalink to “Requirements &amp; Recommendations”">​</a></h2><p>The software was designed to be setup and run as simple as possible. Using the <em><code>config.json</code></em> file you can manage additional settings that are not present in the web client. For example you could configurate a SQL server compatible with MariaDB to improve overall functionality <strong>and unlock all the features</strong>.</p><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>NodeJS / Bun</td><td>In case your machine cant run bun you can also use NodeJS</td></tr><tr><td>MariaDB</td><td><em><strong>Required</strong></em>. <strong><u>MySQL IS NOT COMPATIBLE</u></strong></td></tr><tr><td>SSL / TLS Cert</td><td>You will need a certificate if you try to access it from another machine/internet due to security reasons!</td></tr><tr><td>LiveKit</td><td>Used for voice chatting and screen sharing</td></tr><tr><td>Caddy/nginx</td><td>Used for reverse proxies to make life easier.</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>If you want to follow this tutorial make sure the following is installed:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> curl</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> unzip</span></span></code></pre></div></div><hr><h2 id="downloading-dcts" tabindex="-1">Downloading DCTS <a class="header-anchor" href="#downloading-dcts" aria-label="Permalink to “Downloading DCTS”">​</a></h2><p>You can download and install different versions of DCTS based on your needs. How to best pick a version is explained in the repo Readme.md file.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Download beta version from github</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wget</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/hackthedev/dcts-shipping/archive/refs/heads/beta.zip</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -O</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dcts.zip</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># unzip it</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">unzip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dcts.zip</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># move the unzipped files into the current directory</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dcts-shipping-beta/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dcts-shipping-beta/.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/dev/null</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># delete the old one</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dcts-shipping-beta</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dcts.zip</span></span></code></pre></div><hr><h2 id="installing-bun" tabindex="-1">Installing Bun <a class="header-anchor" href="#installing-bun" aria-label="Permalink to “Installing Bun”">​</a></h2><p>Bun has several <a href="https://bun.com/docs/installation#docker" target="_blank" rel="noreferrer">install methods on their website.</a> You can choose one of the following install methods below.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># maxOS and Linux</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://bun.com/install</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># windows </span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">powershell</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;irm bun.sh/install.ps1|iex&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># via NodeJS&#39; package manager</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bun</span></span></code></pre></div><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>If you&#39;re using old hardware or an otherwise unsupported system or run into weird bun specific issues you can <a href="https://nodejs.org/en/download" target="_blank" rel="noreferrer">install NodeJS</a> as fallback.</p></div><hr><h2 id="running-dcts" tabindex="-1">Running DCTS <a class="header-anchor" href="#running-dcts" aria-label="Permalink to “Running DCTS”">​</a></h2><p>The chat app was made to be very easy to setup and use. Out of the box it should work without any issues. To start the server on both Windows and Linux, navigate to the app&#39;s root directory using a terminal and start the server using <em><code>bun .</code></em></p><p>Example:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># navigate to the project directory</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/dcts</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># install all packages, only required on initial setup</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> i</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># start the server</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span></code></pre></div><p>As you can see all you really need is one command to launch the chat app if the requirements are already installed. This was made with the goal to be very user friendly and easy to setup and use.</p><p>Its possible to use more advanced and better starting methods, such as using docker, a sytem service or supervisor and screen. Information about these can be found in the other documents.</p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>Its important that we launch the server briefly so that the <code>configs/config.json</code> file is automatically generated. The server should automatically terminate itself. If not you can press <code>CTRL + C</code> to terminate it.</p><p>If successful it should tell you to edit the <code>config.json</code> file now which we will do in the next step.</p></div><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>You can run the server with NodeJS as fallback by using the following commands if NodeJS was installed:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># install packages</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> i</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># run the server</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span></code></pre></div></div><hr><h2 id="database-config" tabindex="-1">Database Config <a class="header-anchor" href="#database-config" aria-label="Permalink to “Database Config”">​</a></h2><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p></p><p>You can install MariaDB on linux using <code>apt install mariadb-server mariadb-client -y</code>. For windows and testing only you can use XAMPP</p></div><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>A MariaDB compatible database connection is <strong>required</strong> for DCTS to work.</p></div><p>If you have successfully setup a database server you will need to edit the <code>sql</code> section inside the <code>config.json</code> file. You <strong>must</strong> set <code>enabled</code> to true if thats not the case yet and enter the other information as seen in the example screenshot below. Keep in mind your credentials may be different.</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;sql&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">	&quot;enabled&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">	&quot;host&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;127.0.0.1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">	&quot;username&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;username&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">	&quot;password&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;password&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">	&quot;database&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;dcts&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">	&quot;connectionLimit&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">	&quot;port&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3306</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p></p><p>If you use a database user that has enough permissions DCTS can create the database for you as well.</p><p>The default XAMPP username is <code>root</code> and the password is empty.</p></div><hr><h2 id="accessing-your-chat-app" tabindex="-1">Accessing your chat app <a class="header-anchor" href="#accessing-your-chat-app" aria-label="Permalink to “Accessing your chat app”">​</a></h2><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Once you have made these changes and saved the config file you can now try to start the server again. If you get errors you can restart the server once more and if they are gone you&#39;re good to go.</p></div><p>On default your chat app will run on the port 2052. The port can be changed inside the <em><code>config.json</code></em> file under <em><code>serverinfo.port</code></em>. To access the web client you can open a browser and enter <a href="http://localhost:2052/" target="_blank" rel="noreferrer">http://localhost:2052/</a> if you&#39;re running the chat app locally on your machine.</p><p>Of course if you installed and ran the chat app on your server you would need to replace <em><code>localhost</code></em> with the server&#39;s ip address or domain.</p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>For public access you will need a TLS certificate! This is where caddy becomes relevant. If you installed DCTS on another machine you will need to setup caddy/nginx with TLS certs before progressing from this point on. Checkout <a href="./network/Caddy Setup">Caddy Setup</a>.</p></div><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>Its possible to setup a reverse proxy to get rid of the port in the url. Please check <a href="./network/Reverse Proxy Setup">Reverse Proxy Setup</a> for instructions and carefully read them first!</p></div><div class="caution custom-block github-alert"><p class="custom-block-title">CAUTION</p><p>The DCTS web client and desktop client wont work properly if you or anyone will see this message. It means the browser thinks the connection isnt secure and will therefore block important features of the client.</p><p>Check the above notice for public access.</p></div><p><img src="`+n+'" alt="image-20251108165123275"></p><hr><h2 id="getting-administrator-permissions" tabindex="-1">Getting Administrator permissions <a class="header-anchor" href="#getting-administrator-permissions" aria-label="Permalink to “Getting Administrator permissions”">​</a></h2><p>When you open the chat app for the first time in the web client you will be prompted to register for an account. After that you will notice that you&#39;re just a normal member. In the console you can find a Server Admin Token.</p><p><img src="'+l+'" alt="image-20250201122217494"></p><p>You can use it to redeem the administrator role in the web client. To do so right click any group and click <em><code>Redeem Key</code></em> like in the screenshot. After entering the key you will receive the Administrator role.</p><p><img src="'+o+'" alt="image-20260219182529359"></p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p></p><p>You&#39;ll need to configure and install the software needed for Voice Chatting and Screensharing yourself as of right now. Please checkout <code>VoIP Setup.md</code> inside the <code>docs</code> folder. It will also contain a recommended DNS setup.</p></div><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p></p><p>You can create a new admin token by typing <code>token 1111</code> into the DCTS console window, whereas <code>1111</code> is the role id, in this case the admin role id.</p></div><hr><h2 id="going-public" tabindex="-1">Going Public <a class="header-anchor" href="#going-public" aria-label="Permalink to “Going Public”">​</a></h2><p>If everything works locally and want to go public now so others can access it too then go checkout <a href="./network/Reverse Proxy Setup">Reverse Proxy Setup</a>.</p><p>[^testedNodeVersions]: Checkout Github Main Readme &quot;Tested Versions&quot;</p>',55)])])}const b=i(h,[["render",r]]);export{y as __pageData,b as default};
